# 1. Elevation Check
if (-not ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) {
    Start-Process powershell.exe "-NoProfile -ExecutionPolicy Bypass -File `"$PSCommandPath`"" -Verb RunAs
    exit
}

# --- Hide PowerShell Console Window ---
$memberDefinition = @'
[DllImport("user32.dll")]
public static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);
'@
$typeDefinition = Add-Type -MemberDefinition $memberDefinition -Name "Win32ShowWindow" -Namespace "Win32" -PassThru
$hwnd = (Get-Process -Id $PID).MainWindowHandle
if ($hwnd -ne [IntPtr]::Zero) {
    $typeDefinition::ShowWindow($hwnd, 0) # 0 = SW_HIDE
}

# --- Settings ---
$LogoBase64 = "
" # <--- PASTE YOUR BASE64 STRING HERE
$FilePath = "C:\Program Files (x86)\Radiant Systems\CounterPoint\cpsql.1 - Station\Bin\counterpoint.ini"
$BackupPath = "$FilePath.bak"
$TargetService = "Radiant CounterPoint Services - CPSQL.1"

# --- Functions ---
function Get-CPPath {
    if (Test-Path $FilePath) {
        $lines = Get-Content $FilePath
        foreach ($l in $lines) { if ($l -match "TopLevel=(.*)") { return $Matches[1].Trim() } }
    }
    return "Not Found"
}

function Do-Save($newPath) {
    if (-not (Test-Path $FilePath)) { return "File Missing" }
    try {
        Copy-Item $FilePath $BackupPath -Force
        $c = Get-Content $FilePath
        $out = foreach ($l in $c) { if ($l -match "TopLevel=") { "TopLevel=$newPath" } else { $l } }
        $out | Set-Content $FilePath
        $s = Get-Service -DisplayName $TargetService -ErrorAction SilentlyContinue
        if ($null -ne $s) {
            $confirm = [Windows.Forms.MessageBox]::Show(
                "The path has been saved.`n`nRestart the Counterpoint service now?`nThis will interrupt any active sessions.",
                "Restart Service?",
                [Windows.Forms.MessageBoxButtons]::YesNo,
                [Windows.Forms.MessageBoxIcon]::Warning
            )
            if ($confirm -eq [Windows.Forms.DialogResult]::Yes) {
                Restart-Service -DisplayName $TargetService -Force
            }
        }
        return "Complete"
    } catch { return "Error: $($_.Exception.Message)" }
}

