# --- Logo Reconstruction ---
if ($LogoBase64 -ne "") {
    try {
        $bytes = [Convert]::FromBase64String($LogoBase64)
        $ms = New-Object IO.MemoryStream($bytes, 0, $bytes.Length)
        $logo = [System.Drawing.Image]::FromStream($ms)
        $pb = New-Object System.Windows.Forms.PictureBox
        $pb.Image = $logo
        $pb.Location = "380,20"
        $pb.Size = "100,80"
        $pb.SizeMode = "Zoom"
        $form.Controls.Add($pb)
    } catch { }
}

# Helper to circle the lights
function Make-Circular($ctrl) {
    $path = New-Object System.Drawing.Drawing2D.GraphicsPath
    $path.AddEllipse(0, 0, $ctrl.Width, $ctrl.Height)
    $ctrl.Region = New-Object System.Drawing.Region($path)
}

