# Timer
$timer = New-Object System.Windows.Forms.Timer; $timer.Interval = 3000
$timer.Add_Tick({
    $s = Get-Service -DisplayName $TargetService -ErrorAction SilentlyContinue
    if ($null -eq $s) { $lightSvc.BackColor = "LightGray" }
    elseif ($s.Status -eq "Running") { $lightSvc.BackColor = "LimeGreen" }
    else { $lightSvc.BackColor = "Red" }

    if ($txtNew.Text -match "^\\\\([^\\]+)") {
        if (Test-Connection $Matches[1] -Count 1 -Quiet) { $lightSvr.BackColor = "LimeGreen" }
        else { $lightSvr.BackColor = "Red" }
    } else {
         $lightSvr.BackColor = "LightGray"
    }
})
$timer.Start()

